//! Fixture replay for the admin-audit export beta projection.
//!
//! The fixtures live under `fixtures/security/m3/admin_audit_export/` and are
//! generated by the `aureline_shell_admin_audit_export_beta` headless
//! inspector, so checked-in JSON stays a literal projection of the seeded
//! `AdminAuditExportBetaPage`.

use aureline_shell::admin_audit_export_beta::{
    audit_admin_audit_export_beta_page, seeded_admin_audit_export_beta_page,
    validate_admin_audit_export_beta_page, AdminAuditExportBetaDefectKind,
    AdminAuditExportBetaPage, AdminAuditExportBetaRenderSummary, AdminAuditExportBetaSupportExport,
    EntitlementChangeEvent, PolicyBundleHistoryEvent, ProvisioningEvent,
    ADMIN_AUDIT_EXPORT_BETA_SCHEMA_VERSION, ADMIN_AUDIT_EXPORT_BETA_SHARED_CONTRACT_REF,
};

const FIXTURE_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../fixtures/security/m3/admin_audit_export"
);

fn load<T: serde::de::DeserializeOwned>(filename: &str) -> T {
    let path = format!("{}/{}", FIXTURE_DIR, filename);
    let body =
        std::fs::read_to_string(&path).unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

#[test]
fn page_fixture_matches_seeded_builder() {
    let from_file: AdminAuditExportBetaPage = load("page.json");
    let from_code = seeded_admin_audit_export_beta_page();
    assert_eq!(
        from_file, from_code,
        "fixture must be a literal projection of the seeded page; regenerate via the headless bin"
    );
}

#[test]
fn page_fixture_validates_with_zero_defects() {
    let page: AdminAuditExportBetaPage = load("page.json");
    assert_eq!(
        page.shared_contract_ref,
        ADMIN_AUDIT_EXPORT_BETA_SHARED_CONTRACT_REF
    );
    assert_eq!(page.schema_version, ADMIN_AUDIT_EXPORT_BETA_SCHEMA_VERSION);
    assert!(page.defects.is_empty());
    validate_admin_audit_export_beta_page(&page).expect("seeded page must validate");
}

#[test]
fn provisioning_events_round_trip_and_cover_scim_and_signed_alternatives() {
    let page: AdminAuditExportBetaPage = load("page.json");
    let events: Vec<ProvisioningEvent> = load("provisioning_events.json");
    assert_eq!(page.provisioning_events, events);
    let sources: Vec<&str> = events
        .iter()
        .map(|event| event.source_token.as_str())
        .collect();
    for required in [
        "scim_managed_endpoint",
        "scim_self_hosted_endpoint",
        "signed_file_import",
        "signed_mirror_import",
        "air_gapped_signed_import",
    ] {
        assert!(
            sources.contains(&required),
            "provisioning fixture is missing {required}"
        );
    }
}

#[test]
fn policy_bundle_history_round_trips_and_records_predecessors() {
    let page: AdminAuditExportBetaPage = load("page.json");
    let history: Vec<PolicyBundleHistoryEvent> = load("policy_bundle_history.json");
    assert_eq!(page.policy_bundle_history, history);
    for event in &history {
        if event.transition_token == "replaced_by_successor"
            || event.transition_token == "rolled_back"
        {
            assert!(
                !event.replaces_pack_id.is_empty(),
                "history transition {} must name a predecessor",
                event.event_id
            );
        }
    }
}

#[test]
fn entitlement_changes_round_trip_and_carry_authority_transitions() {
    let page: AdminAuditExportBetaPage = load("page.json");
    let changes: Vec<EntitlementChangeEvent> = load("entitlement_changes.json");
    assert_eq!(page.entitlement_changes, changes);
    let tokens: Vec<&str> = changes
        .iter()
        .map(|event| event.change_token.as_str())
        .collect();
    assert!(tokens.contains(&"granted"));
    assert!(tokens.contains(&"revoked"));
}

#[test]
fn support_export_round_trips_through_validator() {
    let export: AdminAuditExportBetaSupportExport = load("support_export.json");
    assert!(export.raw_private_material_excluded);
    assert!(export.defect_kinds_present.is_empty());
    assert_eq!(
        export.shared_contract_ref,
        ADMIN_AUDIT_EXPORT_BETA_SHARED_CONTRACT_REF
    );
}

#[test]
fn drill_managed_source_missing_signature_replays_typed_defect() {
    let page: AdminAuditExportBetaPage = load("drill_managed_source_missing_signature.json");
    let recomputed = audit_admin_audit_export_beta_page(
        &page.provisioning_events,
        &page.policy_bundle_history,
        &page.entitlement_changes,
    );
    assert_eq!(recomputed, page.defects);
    assert!(recomputed.iter().any(|defect| defect.defect_kind
        == AdminAuditExportBetaDefectKind::ManagedSourceMissingSignature));
}

