#[test]
fn drill_public_fallback_replays_typed_defect() {
    let page: AdminAuditExportBetaPage = load("drill_public_fallback.json");
    let recomputed = audit_admin_audit_export_beta_page(
        &page.provisioning_events,
        &page.policy_bundle_history,
        &page.entitlement_changes,
    );
    assert_eq!(recomputed, page.defects);
    assert!(recomputed
        .iter()
        .any(|defect| defect.defect_kind
            == AdminAuditExportBetaDefectKind::HiddenPublicEndpointFallback));
}

#[test]
fn render_summary_matches_page_summary() {
    let from_file: AdminAuditExportBetaRenderSummary = load("render_summary.json");
    let page: AdminAuditExportBetaPage = load("page.json");
    let from_page = AdminAuditExportBetaRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
